import{_ as a,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"赫刀","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/6.技艺及称号/武技类/白刃类/全集中呼吸法/赫刀.md","filePath":"4.资源分区/6.技艺及称号/武技类/白刃类/全集中呼吸法/赫刀.md"}'),d={name:"4.资源分区/6.技艺及称号/武技类/白刃类/全集中呼吸法/赫刀.md"};function l(b,r,i,p,_,c){return t(),n("div",null,[...r[0]||(r[0]=[e("h1",{id:"赫刀",tabindex:"-1"},[s("赫刀 "),e("a",{class:"header-anchor",href:"#赫刀","aria-label":'Permalink to "赫刀"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：新世短歌036")])])],-1),o('<h1 id="赫刀-1" tabindex="-1">赫刀 <a class="header-anchor" href="#赫刀-1" aria-label="Permalink to &quot;赫刀&quot;">​</a></h1><p>赫刀<br> 技艺<br> B+2000<br> 前置：使用具有星星绯砂铁材质改造的近战武器或日轮刀<br> 出自《鬼灭之刃》<br> 在生死绝境时以强大的意志和握力使具有太阳力量的武器升温，升温并变为红色，展现武器蕴含的太阳之力。<br> 尽管原作该名称叫做赫刀，但鉴于原作已经出现了赫斧与赫流星锤，所以实际上只要使用了蕴含太阳之力的武器都能使用赫刀这一技巧。<br> 开启赫刀需要以一个移动动作爆发绝强握力激发所持用的一把武器的力量，这可以结合在一次不附带技艺的移动中，该检定被称为赫刀检定，你使用展现了赫刀的武器进行攻击附带赫刀检定成功数的器械加值与破甲，如果这些破甲在结算后仍有剩余，则转化为攻击上的器械加值，至多转化赫刀检定成功数点。<br> 赫刀检定是一个纯力量属性检定不计入附加成功，也不计入任何额外加值，无法因其他效果调整成功数。<br> 只要处于赫刀展开状态，以该武器进行攻击在针对【黑暗生物】时视为提升2L武器伤害，总是具有B级创伤来源的B级重伤效果，额外附带攻击出目四分之一的肢体妨碍点数，这些肢体妨碍点数仅在攻击头部时生效。 <br> 展现赫刀后赫刀状态可以持续一场景。</p><p>星星绯砂铁<br> 分类：材质改造<br> 描述：不断吸收太阳光的矿石，锻造出来的武器具有太阳的力量，能够杀死一些畏惧太阳的黑暗生物<br> 价格：500<br> 武器提升：对【黑暗生物】进行攻击时，额外具有【熔毁2】</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',5)])])}const m=a(d,[["render",l]]);export{f as __pageData,m as default};
